observation.old_content:
lexer grammar SYsULexer;

// Keywords
Int : 'int';
Return : 'return';
Void : 'void';
If : 'if';
Else : 'else';
While : 'while';
Break : 'break';
Continue : 'continue';
Const : 'const';

// Brackets and braces
LeftParen : '(';
RightParen : ')';
LeftBracket : '[';
RightBracket : ']';
LeftBrace : '{';
RightBrace : '}';

// Operators
Plus : '+';
Minus : '-';
Star : '*';
Slash : '/';
Percent : '%';

// Assignment
Equal : '=';

// Comparison
Less : '<';
Greater : '>';
LessEqual : '<=';
GreaterEqual : '>=';
EqualEqual : '==';
NotEqual : '!=';

// Logical
And : '&&';
Or : '||';
Exclaim : '!';

// Bitwise
Ampersand : '&';
Pipe : '|';
Caret : '^';
Tilde : '~';
LeftShift : '<<';
RightShift : '>>';

// Increment/Decrement
PlusPlus : '++';
MinusMinus : '--';

// Compound assignment
PlusEqual : '+=';
MinusEqual : '-=';
StarEqual : '*=';
SlashEqual : '/=';
PercentEqual : '%=';
AmpersandEqual : '&=';
PipeEqual : '|=';
CaretEqual : '^=';
LeftShiftEqual : '<<=';
RightShiftEqual : '>>=';

// Ternary
Question : '?';
Colon : ':';

// Other
Arrow : '->';
Dot : '.';
Semi : ';';
Comma : ',';

Identifier
    :   IdentifierNondigit
        (   IdentifierNondigit
        |   Digit
        )*
    ;

fragment
IdentifierNondigit
    :   Nondigit
    ;

fragment
Nondigit
    :   [a-zA-Z_]
    ;

fragment
Digit
    :   [0-9]
    ;

Constant
    :   IntegerConstant
    ;

fragment
IntegerConstant
    :   DecimalConstant
    |   OctalConstant
    |   HexadecimalConstant
    ;

fragment
DecimalConstant
    :   NonzeroDigit Digit*
    ;

fragment
OctalConstant
    :   '0' OctalDigit*
    ;

fragment
HexadecimalConstant
    :   '0' [xX] HexDigit+
    ;

fragment
HexDigit
    :   [0-9a-fA-F]
    ;

fragment
NonzeroDigit
    :   [1-9]
    ;

fragment
OctalDigit
    :   [0-7]
    ;

// Comments - skip them
Comment
    :   '/*' .*? '*/'
        -> skip
    |   '//' ~[\r\n]*
        -> skip
    ;

// 预处理信息处理，可以从预处理信息中获得文件名以及行号
// 预处理信息中的第一个数字即为行号
LineAfterPreprocessing
    :   '#' Whitespace* Digit+ Whitespace+ '"' ~'"'* '"' ~[\r\n]*
        -> skip
    ;

Whitespace
    :   [ \t]+
        -> skip
    ;

// 换行符号，可以利用这个信息来更新行号
Newline
    :   (   '\r' '\n'?
        |   '\n'
        )
        -> skip
    ;

